const source = $('Refund Status Form Webhook').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? $input.first()?.json ?? {};
const query = source.query ?? source;
const headers = source.headers ?? {};
const settings = $('Load Global Settings').first()?.json ?? {};
const allItems = $('List Refunds').all();
const refunds = (allItems && Array.isArray(allItems)) ? allItems.map(n => n.json) : [];
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const updateUrl = `${n8nBaseUrl}/webhook/update-refund-status`;const memberEmailUrl = `${n8nBaseUrl}/webhook/send-member-calculation-email`;const treasuryEmailUrl = `${n8nBaseUrl}/webhook/send-treasury-refund-request`;
const selectedId = parseInt(clean(query.id), 10);
const selectedRefund = refunds.find(r => r.id === selectedId);
const statuses = ['Requested', 'Awaiting Bank Details', 'Bank Details Received', 'Ready For Treasury', 'Sent To Treasury', 'Paid', 'Rejected', 'Cancelled'];
const statusColors = {
  'Requested': '#6b7785',
  'Awaiting Bank Details': '#f2994a',
  'Bank Details Received': '#27ae60',
  'Ready For Treasury': '#27ae60',
  'Sent To Treasury': '#2f80d8',
  'Paid': '#1f7a4d',
  'Rejected': '#b93a3a',
  'Cancelled': '#b93a3a'
};
const formatMoney = (value) => {
  if (value === null || value === undefined) return 'N/A';
  return `£${Number(value).toFixed(2)}`;
};
const formatDate = (value) => {
  if (!value) return 'N/A';
  return new Date(value).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
};
const refundRows = refunds.map(r => {
  const isSelected = r.id === selectedId;
  const statusColor = statusColors[r.status] || '#6b7785';
  return `<tr class="${isSelected ? 'selected' : ''}" onclick="selectRefund(${r.id})">
    <td>${r.id}</td>
    <td>${escapeHtml(r.refund_for)}</td>
    <td>${escapeHtml(r.membership || '')}</td>
    <td>${formatMoney(r.refund)}</td>
    <td><span class="status-badge" style="background:${statusColor}">${escapeHtml(r.status || 'Unknown')}</span></td>
    <td>${formatDate(r.created_at)}</td>
  </tr>`;
}).join('');
const statusOptions = statuses.map(s => `<option value="${escapeHtml(s)}"${selectedRefund && selectedRefund.status === s ? ' selected' : ''}>${escapeHtml(s)}</option>`).join('');
const selectedSection = selectedRefund ? `
  <div class="refund-details">
    <h2>Update Status</h2>
