        <span>${selectedRefund.id}</span>
      </div>
      <div class="detail-row">
        <label>Member</label>
        <span>${escapeHtml(selectedRefund.refund_for)}</span>
      </div>
      <div class="detail-row">
        <label>Membership</label>
        <span>${escapeHtml(selectedRefund.membership || 'N/A')}</span>
      </div>
      <div class="detail-row">
        <label>Reason</label>
        <span>${escapeHtml(selectedRefund.reason || 'N/A')}</span>
      </div>
      <div class="detail-row">
        <label>Amount Paid</label>
        <span>${formatMoney(selectedRefund.amount)}</span>
      </div>
      <div class="detail-row">
        <label>Refund Amount</label>
        <span class="refund-amount">${formatMoney(selectedRefund.refund)}</span>
      </div>
      <div class="form-group">
        <label for="status">Status</label>
        <select name="status" id="status" required>${statusOptions}</select>
      </div>
      <div class="form-group">
        <label for="notes">Notes</label>
        <textarea name="notes" id="notes" rows="3" placeholder="Optional notes about this status change">${escapeHtml(selectedRefund.notes || '')}</textarea>
      </div>
      <div class="email-tracking">
        <h3>Email Tracking</h3>
        <div class="detail-row">
          <label>Request Email ID</label>
          <input type="text" name="request_email_message_id" value="${escapeHtml(selectedRefund.request_email_message_id || '')}" placeholder="Gmail message ID">
        </div>
        <div class="detail-row">
          <label>Bank Details Email ID</label>
          <input type="text" name="bank_details_message_id" value="${escapeHtml(selectedRefund.bank_details_message_id || '')}" placeholder="Gmail message ID">
        </div>
        <div class="detail-row">
          <label>Treasury Email ID</label>
          <input type="text" name="treasury_email_message_id" value="${escapeHtml(selectedRefund.treasury_email_message_id || '')}" placeholder="Gmail message ID">
        </div>
      </div>
      <button type="submit" class="submit-btn">Update Status</button>
    </form>
  </div>
` : '<div class="no-selection"><p>Select a refund from the list to update its status.</p></div>';
