    tr:hover { background: #f8f9fc; }
    tr.selected { background: #eef2f7; }
    .status-badge { display: inline-block; padding: 4px 10px; border-radius: 999px; color: white; font-size: 12px; font-weight: 700; }
    .refund-details { }
    .detail-row { display: flex; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid var(--line); }
    .detail-row label { font-weight: 700; color: var(--muted); }
    .detail-row span { color: var(--ink); }
