    .submit-btn { width: 100%; padding: 14px; background: linear-gradient(135deg, var(--accent) 0%, #2f80d8 100%); color: white; border: none; border-radius: 999px; font-size: 16px; font-weight: 700; cursor: pointer; margin-top: 20px; }
    .submit-btn:hover { opacity: 0.9; }    .email-btn { width: 100%; padding: 14px; background: linear-gradient(135deg, #27ae60 0%, #1e8449 100%); color: white; border: none; border-radius: 999px; font-size: 16px; font-weight: 700; cursor: pointer; margin-top: 12px; }    .email-btn:hover { opacity: 0.9; }    .member-email-section { margin-top: 24px; padding: 20px; background: #f0f9f4; border-radius: 14px; border: 1px solid #c8e6d9; }    .member-email-section h3 { margin: 0 0 8px; color: #1e8449; }    .treasury-btn { width: 100%; padding: 14px; background: linear-gradient(135deg, #2f80d8 0%, #1a5276 100%); color: white; border: none; border-radius: 999px; font-size: 16px; font-weight: 700; cursor: pointer; margin-top: 12px; }    .treasury-btn:hover { opacity: 0.9; }    .treasury-email-section { margin-top: 24px; padding: 20px; background: #eaf2f8; border-radius: 14px; border: 1px solid #c3d9e6; }    .treasury-email-section h3 { margin: 0 0 8px; color: #1a5276; }    .treasury-email-section p { margin: 0 0 16px; color: #2e3d4e; font-size: 14px; }    .checkbox-wrap { display: inline-flex; align-items: center; gap: 10px; font-weight: 600; margin-top: 8px; }    .checkbox-wrap input { width: 18px; height: 18px; }    .member-email-section p { margin: 0 0 16px; color: #2e3d4e; font-size: 14px; }
